const body = $input.first().json.body;

// No schema provided, use permissive default
if (!body.output_schema) {
  return [{
    json: {
      prompt: body.prompt,
      output_schema: {
        type: "object",
        additionalProperties: true
      }
    }
  }];
}

// Validate the provided schema
const schema = body.output_schema;

if (typeof schema !== "object" || Array.isArray(schema)) {
  throw new Error("output_schema must be a JSON object");
}

if (!schema.type) {
  throw new Error("output_schema must have a 'type' property");
}

const validTypes = ["object", "array", "string", "number", "boolean"];
if (!validTypes.includes(schema.type)) {
  throw new Error(`output_schema.type must be one of: ${validTypes.join(", ")}`);
}

// Schema is valid, pass it through
return [{
  json: {
    prompt: body.prompt,
    output_schema: schema
  }
}];

